import{_ as n,o as r,c as a,a0 as t}from"./chunks/framework.AQcSKqPn.js";const h=JSON.parse(`{"title":"Sousou no Frieren (Frieren: Beyond Journey's End) — MyAnimeList Entry","description":"","frontmatter":{"type":"source","title":"Sousou no Frieren (Frieren: Beyond Journey's End) — MyAnimeList Entry","tags":["anime","fantasy","drama","adventure","award-winning"],"related":["sousou-no-frieren","frieren","long-lived-time-perception","post-adventure-narrative"],"sources":["anime/52991.md"],"created":"2026-07-10T00:00:00.000Z","updated":"2026-07-10T00:00:00.000Z","authors":[],"year":2023,"url":"https://myanimelist.net/anime/52991","venue":"MyAnimeList"},"headers":[],"relativePath":"sources/5-anime--5-52991--tdvct7.md","filePath":"sources/5-anime--5-52991--tdvct7.md","lastUpdated":1783752184000}`),i={name:"sources/5-anime--5-52991--tdvct7.md"};function o(s,e,l,d,u,m){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="sousou-no-frieren-frieren-beyond-journey-s-end-—-myanimelist-entry" tabindex="-1">Sousou no Frieren (Frieren: Beyond Journey&#39;s End) — MyAnimeList Entry <a class="header-anchor" href="#sousou-no-frieren-frieren-beyond-journey-s-end-—-myanimelist-entry" aria-label="Permalink to &quot;Sousou no Frieren (Frieren: Beyond Journey&#39;s End) — MyAnimeList Entry&quot;">​</a></h1><p>《葬送的芙莉莲》（英文标题 <em>Frieren: Beyond Journey&#39;s End</em>）是一部2023年播出的日本动画作品，改编自由山田钟人原作、阿部司作画的同名漫画。本条目基于MyAnimeList（MAL）元数据与剧情摘要。</p><h2 id="元数据" tabindex="-1">元数据 <a class="header-anchor" href="#元数据" aria-label="Permalink to &quot;元数据&quot;">​</a></h2><ul><li><strong>MAL ID</strong>: 52991</li><li><strong>评分</strong>: 9.26（极高评分，MAL历史最高分之一）</li><li><strong>集数</strong>: 28集（已完结播出）</li><li><strong>状态</strong>: Finished Airing</li><li><strong>类型</strong>: Adventure, Award Winning, Drama, Fantasy</li><li><strong>首播年份</strong>: 2023</li></ul><h2 id="剧情概要" tabindex="-1">剧情概要 <a class="header-anchor" href="#剧情概要" aria-label="Permalink to &quot;剧情概要&quot;">​</a></h2><p>在长达十年的讨伐魔王之旅中，勇者辛美尔、僧侣海塔、矮人战士艾泽与精灵魔法使芙莉莲结下了深厚羁绊。然而，对已度过千年岁月的芙莉莲而言，与同伴共处的时光仅是她漫长生命中的一瞬。魔王被击败、队伍解散后，芙莉莲重返故地，开始重新审视那段&quot;短暂&quot;冒险的意义，并踏上理解人类情感与时间的新旅程。</p><h2 id="叙事特点" tabindex="-1">叙事特点 <a class="header-anchor" href="#叙事特点" aria-label="Permalink to &quot;叙事特点&quot;">​</a></h2><p>作品将传统奇幻故事中&quot;击败魔王&quot;的终点作为叙事的起点，聚焦于冒险后的日常生活与角色间的情感余韵。这种<a href="/llm-wiki/concepts/冒险后的叙事-post-adventure-narrative">post-adventure-narrative</a>结构颠覆了常规奇幻叙事范式，是其获得广泛好评的核心创新之一。</p><h2 id="主题关联" tabindex="-1">主题关联 <a class="header-anchor" href="#主题关联" aria-label="Permalink to &quot;主题关联&quot;">​</a></h2><p>作品深入探讨了<a href="/llm-wiki/concepts/长寿种的时间感知-long-lived-time-perception">long-lived-time-perception</a>——精灵与人类在时间尺度上的巨大差异如何影响情感体验、记忆价值与人生意义。这一主题贯穿全剧，驱动角色成长与剧情发展。</p><h2 id="备注" tabindex="-1">备注 <a class="header-anchor" href="#备注" aria-label="Permalink to &quot;备注&quot;">​</a></h2><ul><li>动画已完结（28集），但原作漫画仍在连载中。</li><li>评分9.26为截至2023年播出期间的数据，可能随后续观众评价而波动。</li><li>本条目仅基于MAL元数据与剧情摘要，未涵盖完整剧情分析或角色深度解读。</li></ul>',12)])])}const p=n(i,[["render",o]]);export{h as __pageData,p as default};
